// Transmission Lines -- glowing fiber bundle with traveling light pulses.
uniform vec4 uFiber;   // x=strands, y=bundleWidth, z=vanishDepth, w=glassGlow
uniform vec4 uPulse;   // x=pulseSpeed, y=pulseDensity, z=pulseLength, w=time(=absTime*Speed)
uniform vec4 uLook;    // x=haze, y=dof, z=ptpRate, w=absTime
out vec4 fragColor;
const float PI = 3.14159265;

float hash11(float p){ return fract(sin(p*127.1)*43758.5453); }

// per-strand color: mostly cyan, a few green/magenta/amber essence channels
vec3 strandColor(float i){
    float k = mod(i, 7.0);
    if(k < 4.0) return vec3(0.00, 0.85, 1.00);   // cyan hero
    if(k < 5.0) return vec3(0.20, 1.00, 0.42);   // green
    if(k < 6.0) return vec3(1.00, 0.20, 0.62);   // magenta
    return vec3(1.00, 0.70, 0.10);               // amber
}

void main(){
    vec2 uv = vUV.st;
    float aspect = uTDOutputInfo.res.z / uTDOutputInfo.res.w;
    vec2 p = vec2((uv.x-0.5)*aspect, uv.y-0.5);

    vec3 col = mix(vec3(0.010,0.012,0.016), vec3(0.02,0.024,0.03), 1.0 - length(p)); // charcoal ground

    float nS    = clamp(uFiber.x, 1.0, 28.0);
    float bw    = uFiber.y;
    float vDepth= uFiber.z;
    float gglow = uFiber.w;
    float t     = uPulse.w;
    float pdens = uPulse.y;
    float plen  = uPulse.z;
    float haze  = uLook.x;
    float dof   = uLook.y;

    // vanishing point toward the right-center (signal flow l->r into the distance)
    vec2 vp = vec2(0.45*aspect, 0.02);

    const int MAXS = 28;
    for(int i=0;i<MAXS;i++){
        if(float(i) >= nS) break;
        float fi = float(i);
        float depth = fi / max(1.0, nS-1.0);        // 0 = near (foreground), 1 = far
        float sd = hash11(fi*3.1);

        // strand baseline: spread vertically near the camera, converge to vp far away
        float y0 = (sd*2.0-1.0) * bw;
        // smooth curve from a left spread point to the vanishing point
        vec2 a = vec2(-0.6*aspect, y0);
        vec2 b = vp;
        // gentle bow so strands read as relaxed cable, not laser-straight
        vec2 bow = vec2(0.0, (hash11(fi*7.7)*2.0-1.0)*0.12);
        vec2 mid = mix(a,b,0.5) + bow;

        // project p onto the quadratic curve by sampling s and taking the min distance
        float best = 1e9; float bestS = 0.0;
        const int STEPS = 24;
        for(int j=0;j<=STEPS;j++){
            float s = float(j)/float(STEPS);
            float u = 1.0-s;
            vec2 cp = u*u*a + 2.0*u*s*mid + s*s*b;
            float d = length(p - cp);
            if(d < best){ best = d; bestS = s; }
        }

        // width + brightness fall off with depth (perspective + haze)
        float w = mix(0.014, 0.003, depth);
        float dofBlur = 1.0 + dof * abs(depth - 0.0) * 6.0;   // near strands sharper; tweak
        w *= mix(1.0, dofBlur, 0.5);

        vec3 sc = strandColor(fi);
        // glass tube: thin core + internal-reflection gradient (brighter on one edge)
        float tube = smoothstep(w, 0.0, best);
        float refl = smoothstep(w*3.0, 0.0, best) * (0.5 + 0.5*sin(bestS*40.0 + t*2.0));
        float dim = mix(1.0, 0.25, depth);                  // far strands dim into haze
        col += sc * (tube*0.20 + refl*0.10*gglow) * dim;

        // traveling light pulses: bright Gaussian dashes along bestS, advancing + wrapping
        float speedJ = 0.6 + 0.6*hash11(fi*4.2);
        for(int k=0;k<6;k++){
            float fk = float(k);
            float phase = fract(hash11(fi*9.0+fk*2.3) + t*speedJ);
            float along = bestS - phase;
            // pulse only where we are ON the strand
            float onStrand = smoothstep(w*2.5, 0.0, best);
            float pulse = exp(-pow(along/plen, 2.0)*30.0) * onStrand;
            // density gate: only render this pulse if it's in the active set
            if(fk < pdens){
                vec3 core = mix(sc, vec3(1.0), 0.6);        // white-hot core
                col += core * pulse * dim * 1.6;
            }
        }
    }

    // PTP beat: all pulses breathe brighter in lockstep
    float beat = fract(uLook.w * uLook.z);
    float flash = pow(max(0.0, 1.0 - beat*4.0), 3.0);
    col *= 1.0 + 0.4*flash;

    // atmospheric haze toward the vanishing point + edge falloff
    float toVP = length(p - vp);
    col += vec3(0.02,0.03,0.04) * haze * smoothstep(0.6, 0.0, toVP);
    col *= mix(1.0, 0.55, smoothstep(0.5, 1.0, length(p)));

    fragColor = vec4(max(col, 0.0), 1.0);
}

// Volumetric bloom + scanline + grain finish.
uniform vec4 uBloom;   // x=strength, y=threshold
out vec4 fragColor;
float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;
    vec3 src = texture(sTD2DInputs[0], uv).rgb;
    float thr = uBloom.y;
    vec3 sum = vec3(0.0); float wsum = 0.0;
    const int R = 7;
    for(int x=-R;x<=R;x++){
        for(int y=-R;y<=R;y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/24.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*2.5).rgb;
            sum += max(s - thr, 0.0) * w;
            wsum += w;
        }
    }
    vec3 col = src + (sum/max(wsum,1e-4)) * uBloom.x;
    float scan = 0.97 + 0.03*sin(uv.y * uTDOutputInfo.res.w * 3.14159);
    col *= scan;
    col += (hash21(uv*uTDOutputInfo.res.zw)-0.5) * 0.012;
    fragColor = vec4(col, 1.0);
}
